public class XHyperlinkStateNotesWidget extends XAbstractHyperlinkLabelCmdValueSelWidget {   public static WidgetId ID = WidgetIdAts.XHyperlinkStateNotesWidget;   private String shortStr;   private AtsStateNote note;   private IAtsWorkItem workItem;   public XHyperlinkStateNotesWidget() {      super(ID, "");   }   public XHyperlinkStateNotesWidget(String shortStr, String shortStr2, IAtsWorkItem workItem, AtsStateNote note) {      super(ID, shortStr);      this.shortStr = shortStr;      this.workItem = workItem;      this.note = note;   }   @Override   public String getCurrentValue() {      return shortStr;   }   @Override   public boolean handleSelection() {      EntryDialog ed = new EntryDialog(Displays.getActiveShell(), "View/Update State Note", null, "Enter State Notes",         MessageDialog.QUESTION, new String[] {"Remove", "Update", "Cancel"}, 2);      ed.setFillVertically(true);      ed.setEntry(note.getMsg());      int result = ed.open();      if (result == 0) {         return AtsApiService.get().getWorkItemService().getStateNoteService().removeNote(workItem, note);      } else if (result == 1) {         return AtsApiService.get().getWorkItemService().getStateNoteService().updateNote(workItem, note,            ed.getEntry());      }      return false;   }}